import React, { Component } from 'react';
import './Btn.css';

class Btn extends Component {

    openWindow = () => {
        window.open(link, '_blank');
    };

    render() {
        const {
            title,
            link
        } = this.props;

        return (
            <button className="Btn" onClick={this.openWindow()}>
                <div className="Btn-title">{title}</div>
            </button>
        );
    }
}

export default Btn;
